/*
 * Command line interface to the crypt(3) family of routines.
 */

#include <err.h>
#include <pwd.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>

static char *mksalt(void);
static void usage(void);

/*
 * Returns pointer to static buffer.
 */
static char *
mksalt(void)
{
	static char output[33];
	static const char range[] =
	    "abcdefghijklmnopqrstuvwxyz"
	    "0123456789"
	    "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
	char *p;

	for (p = output; p < output + sizeof(output) - 1; p++)
		*p = range[arc4random() % (sizeof(range) - 1)];
	output[sizeof(output) - 1] = '\0';
	return (output);
}

static void
usage(void)
{

	fprintf(stderr, "Usage: %s [-n] [-f type] [-s salt] [password ...]\n",
	    getprogname());
	exit(1);
}

int
main(int ac, char **av)
{
	int newline, passfree;		/* Output trailing NL?  free() pass? */
	char *salt, *pass;       	/* Arguments to crypt(3). */
	char *sum;			/* crypt(3) result. */
	char c;
	char *p, **xp;
	int passlen, rv;

	newline = 1;
	salt = NULL;
	while ( (c = getopt(ac, av, "f:ns:")) != -1)
		switch (c) {
		case 'f':
			rv = crypt_set_format(optarg);
			if (rv == 0)
				errx(1, "invalid format: %s", optarg);
			break;
		case 'n':
			newline = 0;
			break;
		case 's':
			salt = optarg;
			break;
		default:
			usage();
		}
	ac -= optind;
	av += optind;

	if (salt == NULL)
		salt = mksalt();

	if (ac == 0) {
		pass = getpass("Password: ");
		passfree = 0;
	} else {
		passlen = 0;
		for (xp = av; xp < &av[ac]; xp++)
			passlen += strlen(*xp);
		passlen += ac + 1; /* XXX is this right? */
		pass = malloc(passlen);
		pass[0] = '\0';
		for (xp = av; xp < &av[ac]; xp++) {
			strlcat(pass, *xp, passlen);
			strlcat(pass, " ", passlen);
		}
		p = strchr(pass, '\0');
		*--p = '\0';
		passfree = 1;
	}

	sum = crypt(pass, salt);
	printf("%s%s", sum, newline ? "\n" : "");

	if (passfree)
		free(pass);
	return (0);
}
